3	export function nextGeneration(cells: Cell[]): Cell[] {
4	  const liveSet = new Set<string>();
5	  for (const [x, y] of cells) {
6	    liveSet.add(`${x},${y}`);
7	  }
8	
9	  const neighborCounts = new Map<string, number>();
10	
11	  for (const [x, y] of cells) {
12	    for (let dx = -1; dx <= 1; dx++) {
13	      for (let dy = -1; dy <= 1; dy++) {
14	        if (dx === 0 && dy === 0) continue;
15	        const nx = x + dx;
16	        const ny = y + dy;
17	        const key = `${nx},${ny}`;
18	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
19	      }
20	    }
21	  }
22	
23	  const result: Cell[] = [];
24	  for (const [key, count] of neighborCounts) {
25	    const isAlive = liveSet.has(key);
26	    if (count === 3 || (isAlive && count === 2)) {
27	      const [xStr, yStr] = key.split(',');
28	      result.push([Number(xStr), Number(yStr)]);
29	    }
30	  }
31	
32	  return result;
33	}
